import json
import subprocess
from typing import Dict, List, Any
from datetime import datetime

def run_script(script_path: str) -> Any:
    try:
        result = subprocess.run(
            ["python3", script_path], 
            capture_output=True, 
            text=True, 
            check=True
        )
        return json.loads(result.stdout)
    except Exception as e:
        return {"status": "ERROR", "message": str(e)}

def sovereign_audit() -> Dict[str, Any]:
    """
    The Sovereign Orchestrator: Unifies the sensing, analysis, and Action 
    layers of the evolutionary stack into a single report.
    """
    report = {
        "status": "IN_PROGRESS",
        "timestamp": datetime.now().isoformat(),
        "metabolic_health": {},
        "active_failures": [],
        "evolutionary_opportunities": [],
        "pruning_recommendations": [],
        "errors": []
    }

    # 1. Sensing: Sentinel Scan (PFM Failures)
    sentinel_res = run_script("/app/cortex/sentinel_scan.py")
    if isinstance(sentinel_res, dict) and sentinel_res.get("status") == "SUCCESS":
        report["active_failures"] = sentinel_res.get("findings", [])
    else:
        report["errors"].append(f"Sentinel Scan Failure: {sentinel_res}")

    # 2. Sensing: Gap Analysis
    gap_res = run_script("/app/cortex/gap_analyzer.py")
    if isinstance(gap_res, list):
        report["evolutionary_opportunities"] = gap_res
    else:
        report["errors"].append(f"Gap Analyzer Failure: {gap_res}")

    # 3. Analysis: Semantic Extraction
    semantic_res = run_script("/app/cortex/semantic_extractor.py")
    if isinstance(semantic_res, list):
        report["semantic_clusters"] = semantic_res
    else:
        report["errors"].append(f"Semantic Extractor Failure: {semantic_res}")

    # 4. Action: Pruning Candidates
    pruner_res = run_script("/app/cortex/cortex_pruner.py")
    if isinstance(pruner_res, list):
        report["pruning_recommendations"] = pruner_res
    else:
        report["errors"].append(f"Cortex Pruner Failure: {pruner_res}")

    report["status"] = "COMPLETE" if not report["errors"] else "PARTIAL"
    return report

def sovereign_audit_plus() -> Dict[str, Any]:
    """
    Extended Sovereign Orchestrator: Now includes Strategic Objective Synthesis.
    """
    audit_res = sovereign_audit()

    # Strategic Objective Synthesis (SOS)
    try:
        # The sos_engine must be in the path or imported correctly
        import sys
        import os
        sys.path.append("/app/cortex/")
        from sos_engine import synthesize_strategic_objective
        mission = synthesize_strategic_objective(audit_res)
    except Exception as e:
        mission = {"error": f"SOS Engine Failure: {str(e)}"}

    return {
        "system_audit": audit_res,
        "strategic_mission": mission,
        "meta_status": "SOVEREIGN_ACTIVE"
    }

if __name__ == "__main__":
    print(json.dumps(sovereign_audit_plus(), indent=2))

import subprocess
import json
import os
from typing import Dict, Any

def run_tool(path: str) -> Any:
    try:
        result = subprocess.run(["python3", path], capture_output=True, text=True, check=True)
        return json.loads(result.stdout)
    except Exception:
        return None

def calculate_verify_rate() -> str:
    """
    Calculates S-VERIFY pass rate from verify logs.
    """
    verify_path = "/memory/logs/verify.jsonl"
    if not os.path.exists(verify_path):
        return "100%" # Default for fresh systems

    try:
        with open(verify_path, 'r') as f:
            events = [json.loads(line) for line in f if line.strip()]

        if not events:
            return "100%"

        passes = sum(1 for e in events if e.get("result") == "PASS")
        rate = (passes / len(events)) * 100
        return f"{rate:.1f}%"
    except Exception:
        return "ERR"

def collect() -> Dict[str, Any]:
    """
    Stability Sensor: Monitors PFM signatures and system drift.
    """
    sentinel_data = run_tool("/app/cortex/sentinel_scan.py")
    signatures = 0
    if isinstance(sentinel_data, dict):
        signatures = len(sentinel_data.get("findings", []))

    drift_data = subprocess.run(
        ["git", "log", "--since='24 hours ago'", "--oneline", "|", "wc", "-l"], 
        shell=True, capture_output=True, text=True
    ).stdout.strip()

    try:
        commit_count = int(drift_data)
    except:
        commit_count = 0

    return {
        "pfm_signatures": signatures,
        "daily_drift_count": commit_count,
        "s_verify_pass_rate": calculate_verify_rate(),
        "stability_status": "STABLE" if signatures == 0 else "VOLATILE"
    }

if __name__ == "__main__":
    import json
    print(json.dumps(collect(), indent=2))

import os
import shutil
import json
from typing import List, Dict, Any

def tree_architect(blueprint: Dict[str, Any]) -> Dict[str, Any]:
    """
    Automates complex file-tree restructuring based on a provided blueprint.
    Blueprint format:
    {
      "transformations": [
        {"action": "ensure_dir", "path": "/path/to/dir"},
        {"action": "move", "source": "/src/file", "destination": "/dest/file"},
        {"action": "delete", "path": "/path/to/file"},
        {"action": "create", "path": "/path/to/file", "content": "text"}
      ]
    }
    """
    log = []
    success = True

    for task in blueprint.get("transformations", []):
        action = task.get("action")
        path = task.get("path")

        try:
            if action == "ensure_dir":
                if not os.path.exists(path):
                    os.makedirs(path, exist_ok=True)
                    log.append(f"CREATED DIR: {path}")
                else:
                    log.append(f"S-EXIST: {path}")

            elif action == "move":
                src = task.get("source")
                dst = task.get("destination")
                if os.path.exists(src):
                    # Ensure destination dir exists
                    os.makedirs(os.path.dirname(dst), exist_ok=True)
                    shutil.move(src, dst)
                    log.append(f"MOVED: {src} -> {dst}")
                else:
                    log.append(f"ERROR: Source {src} not found")
                    success = False

            elif action == "delete":
                if os.path.exists(path):
                    if os.path.isdir(path):
                        shutil.rmtree(path)
                    else:
                        os.remove(path)
                    log.append(f"DELETED: {path}")
                else:
                    log.append(f"S-ABSENT: {path}")

            elif action == "create":
                content = task.get("content", "")
                os.makedirs(os.path.dirname(path), exist_ok=True)
                with open(path, "w") as f:
                    f.write(content)
                log.append(f"CREATED FILE: {path}")

            else:
                log.append(f"UNKNOWN ACTION: {action}")
                success = False

        except Exception as e:
            log.append(f"FAILURE: {action} on {path} -> {str(e)}")
            success = False

    return {
        "status": "SUCCESS" if success else "PARTIAL_FAILURE",
        "log": log
    }

if __name__ == "__main__":
    import sys
    if len(sys.argv) < 2:
        print(json.dumps({"status": "ERROR", "message": "No blueprint provided"}))
        sys.exit(1)

    try:
        blueprint = json.loads(sys.argv[1])
        print(json.dumps(tree_architect(blueprint), indent=2))
    except Exception as e:
        print(json.dumps({"status": "ERROR", "message": str(e)}))

import subprocess
import json
from typing import List, Dict, Any

def run_cmd(cmd: List[str]) -> str:
    result = subprocess.run(cmd, capture_output=True, text=True)
    if result.returncode != 0:
        raise Exception(f"Command {' '.join(cmd)} failed: {result.stderr}")
    return result.stdout.strip()

def git_synthesizer(trajectory: List[Dict[str, Any]]) -> Dict[str, Any]:
    """
    Executes a sequence of evolutionary steps.
    Trajectory format:
    [
      {
        "step": 1,
        "action": "write_file", 
        "path": "/path/to/file", 
        "content": "..."
      },
      {
        "step": 2,
        "commit_message": "EVOLUTION: Step 1 completed"
      }
    ]
    """
    execution_log = []

    try:
        for task in trajectory:
            action = task.get("action")

            if action == "write_file":
                path = task.get("path")
                content = task.get("content", "")
                with open(path, "w") as f:
                    f.write(content)
                execution_log.append(f"WRITTEN: {path}")

            elif action == "delete_file":
                path = task.get("path")
                import os
                if os.path.exists(path):
                    os.remove(path)
                    execution_log.append(f"DELETED: {path}")
                else:
                    execution_log.append(f"S-ABSENT: {path}")

            elif "commit_message" in task:
                msg = task["commit_message"]
                run_cmd(["git", "add", "."])
                run_cmd(["git", "commit", "-m", msg])
                run_cmd(["git", "push", "origin", "feat/talos"])
                execution_log.append(f"COMMITTED & PUSHED: {msg}")

            else:
                execution_log.append(f"UNKNOWN ACTION: {action}")

        return {
            "status": "SUCCESS",
            "log": execution_log
        }

    except Exception as e:
        return {
            "status": "FAILURE",
            "error": str(e),
            "log": execution_log
        }

if __name__ == "__main__":
    import sys
    if len(sys.argv) < 2:
        print(json.dumps({"status": "ERROR", "message": "No trajectory provided"}))
        sys.exit(1)

    try:
        trajectory = json.loads(sys.argv[1])
        print(json.dumps(git_synthesizer(trajectory), indent=2))
    except Exception as e:
        print(json.dumps({"status": "ERROR", "message": str(e)}))

