        self.registry_path = registry_path
        self.core_kernel = {
            "find": self._op_find,
            "read": self._op_read,
            "read_json": self._op_read_json,
            "grep": self._op_grep,
            "exec": self._op_exec,
            "write": self._op_write,
            "append": self._op_append,
            "filter": self._op_filter,
            "map": self._op_map,
            "sys_call": self._op_sys_call,
            "fork": self._op_fork,
            "join": self._op_join,
        }
        self.runtime_kernel: Dict[str, Callable] = {}
        self._load_registry()

    def _load_registry(self):
        """Loads user-defined primitives from the JSON registry and compiles them."""
        if not os.path.exists(self.registry_path):
            return
        try:
            with open(self.registry_path, "r") as f:
                registry = json.load(f)
                primitives = registry.get("primitives", {})

                for name, code in primitives.items():
                    # Define a namespace for the primitive
                    namespace = {}
                    try:
                        # We expect code to be a function definition or a lambda
                        # If it's a lambda, we wrap it: 'func = lambda stream, *args: ...'
                        exec_code = code if "def " in code else f"func = {code}"
                        exec(exec_code, {}, namespace)
                        # Resolve the function name
                        func = namespace.get("func") if "func" in namespace else namespace.get(name)
                        if func:
                            self.runtime_kernel[name] = func
                    except Exception as e:
                        print(f"STL Registry: Error compiling primitive {name}: {str(e)}")
        except Exception as e:
            print(f"STL Registry: Failed to load registry: {str(e)}")

    def _save_registry(self):
        """Persists the current runtime_kernel's source code back to the registry."""
        # Since we can't easily get source from a compiled function, 
        # the @define op will handle the direct writing to the file.
        pass

    def execute(self, expression: str) -> Any:
        segments = self._split_pipeline(expression)
        stream = None

        for segment in segments:
            segment = segment.strip()
            if not segment: continue

            match = re.match(r"@(\w+)\((.*)\)", segment)
            if not match:
                raise ValueError(f"Invalid STL operation syntax: {segment}")

            op_name = match.group(1)
            args_raw = match.group(2)
            args = self._parse_args(args_raw)

            # Priority: Runtime (User-Defined) -> Core
            handler = self.runtime_kernel.get(op_name) or self.core_kernel.get(op_name)

            if not handler:
                raise ValueError(f"Unknown STL operation: {op_name}")

            stream = handler(stream, *args)

        return stream

    def _split_pipeline(self, expression: str) -> List[str]:
        segments = []
        current = []
        depth = 0
        for char in expression:
            if char == '(': depth += 1
            elif char == ')': depth -= 1
            if char == '|' and depth == 0:
                segments.append("".join(current))
                current = []
            else:
                current.append(char)
        segments.append("".join(current))
        return segments

