    def _op_define(self, stream: Any, name: str, code: str) -> str:
        """
        Sovereign Definition: Injects a new primitive into the STL engine.
        Syntax: @define('my_op', 'lambda stream, x: x + 1')
        """
        # 1. Save to registry file
        try:
            with open(self.registry_path, "r") as f:
                registry = json.load(f)

            registry["primitives"][name] = code

            with open(self.registry_path, "w") as f:
